code_changes.content:
[
  {
    "file": "internal/terraform/context_apply.go",
    "line": 150,
    "severity": "critical",
    "description": "Hook return values are ignored when calling PreApplyImport and PostApplyImport. These methods return (HookAction, error), and HookActionHalt should stop further processing. The code calls both hooks unconditionally without checking HookActionHalt or handling errors, violating the hook contract. This is a cross-file interaction bug where context_apply.go breaks assumptions defined in hook.go.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -147,10 +147,32 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts
 			for _, h := range c.hooks {
 				// In future, we may need to call PostApplyImport separately elsewhere in the apply
 				// operation. For now, though, we'll call Pre and Post hooks together.
-				h.PreApplyImport(hookResourceID, *rc.Importing)
-				h.PostApplyImport(hookResourceID, *rc.Importing)
+				action, err := h.PreApplyImport(hookResourceID, *rc.Importing)
+				if err != nil {
+					diags = diags.Append(tfdiags.Sourceless(
+						tfdiags.Error,
+						"Hook error during import",
+						fmt.Sprintf("PreApplyImport hook failed: %s", err),
+					))
+				}
+				if action == HookActionHalt {
+					break
+				}
+
+				action, err = h.PostApplyImport(hookResourceID, *rc.Importing)
+				if err != nil {
+					diags = diags.Append(tfdiags.Sourceless(
+						tfdiags.Error,
+						"Hook error during import",
+						fmt.Sprintf("PostApplyImport hook failed: %s", err),
+					))
+				}
+				if action == HookActionHalt {
+					break
+				}
 			}
 		}
 	}
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 200,
    "severity": "high",
    "description": "Ephemeral value handling is inconsistent: when a non-ephemeral variable receives an ephemeral-marked value, the code appends an error diagnostic saying 'Ephemeral value not allowed' but then returns the ephemeral-marked value anyway. This contradicts the error message and is inconsistent with how other validation errors are handled in this function (which return cty.UnknownVal placeholders). The ephemeral mark propagates through even after the error rejection, potentially causing downstream evaluation errors in unexpected places.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -213,6 +213,14 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *I
 			diags = diags.Append(&hcl.Diagnostic{
 				Severity: hcl.DiagError,
 				Summary:  "Ephemeral value not allowed",
 				Detail:   "This input variable is not declared as accepting a ephemeral values, so it cannot be set to a result derived from an ephemeral value.",
 				Subject:  subject.Ptr(),
 			})
+			// Return a placeholder unknown value to avoid producing
+			// redundant downstream errors and to prevent the ephemeral mark
+			// from propagating through a variable that explicitly rejects it.
+			val = cty.UnknownVal(cfg.Type)
 		}
 	}

"
  },
  {
    "file": "internal/terraform/context_apply.go",
    "line": 316,
    "severity": "medium",
    "description": "Apply-time variable validation is incomplete: The code has a FIXME comment (lines 316-318) stating 'We should check that all of these match declared variables and that all of them are declared as ephemeral', but the actual validation is not implemented. Non-ephemeral variables can be passed during apply phase, violating the stated requirement that only ephemeral variables should be settable during apply (since non-ephemeral variables must retain their plan-time values). This allows incorrect apply behavior that violates the plan-apply consistency contract.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -313,10 +313,33 @@ func (c *Context) applyGraph(plan *plans.Plan, config *configs.Config, opts *A
 	}
 	// Apply-time variables need to be merged in too.
-	// FIXME: We should check that all of these match declared variables and
-	// that all of them are declared as ephemeral, because all non-ephemeral
-	// variables are supposed to come exclusively from plan.VariableValues.
+	// Validate that all apply-time variables are declared and ephemeral.
 	if opts != nil {
+		for n := range opts.SetVariables {
+			if _, exists := config.Module.Variables[n]; !exists {
+				diags = diags.Append(tfdiags.Sourceless(
+					tfdiags.Error,
+					"Unknown variable",
+					fmt.Sprintf("Apply-time variable %q is not declared in the configuration.", n),
+				))
+				continue
+			}
+			if !config.Module.Variables[n].Ephemeral {
+				diags = diags.Append(tfdiags.Sourceless(
+					tfdiags.Error,
+					"Non-ephemeral variable during apply",
+					fmt.Sprintf(
+						"Variable %q is not declared as ephemeral. Non-ephemeral variables must retain their plan-time values and cannot be reset during apply.",
+						n,
+					),
+				))
+			}
+		}
+	}
+
+	if opts != nil {
 		for n, vv := range opts.SetVariables {
 			variables[n] = vv
 		}
"
  }
]

